      "materia_id": "M24_contabilita_tributaria_avanzata",
      "argomento_id": "A100_split_reverse_charge",
      "materia": "Contabilità Tributaria Avanzata — Accertamento, Rimborsi, Split Payment",
      "normativa": "art. 17 co. 5-6 DPR 633/1972; D.Lgs. 118/2011",
